namespace RVT_SystemCarePro
{
    static class Program
    {
        [STAThread]
        static void Main()
        {
            try
            {
                Application.EnableVisualStyles();
                Application.SetCompatibleTextRenderingDefault(false);
                Application.ThreadException += (s, e) =>
                {
                    try { File.WriteAllText(Path.Combine(Application.StartupPath, "RVT_crash.log"), "ThreadException: " + e.Exception.ToString()); } catch { }
                    MessageBox.Show("Error: " + e.Exception.Message, "RVT System Care Pro", MessageBoxButtons.OK, MessageBoxIcon.Error);
                };
                AppDomain.CurrentDomain.UnhandledException += (s, e) =>
                {
                    Exception ex = e.ExceptionObject as Exception;
                    string msg = ex != null ? ex.ToString() : "Unknown";
                    try { File.WriteAllText(Path.Combine(Application.StartupPath, "RVT_crash.log"), "Fatal: " + msg); } catch { }
                    MessageBox.Show("Fatal: " + (ex != null ? ex.Message : "Unknown"), "RVT System Care Pro", MessageBoxButtons.OK, MessageBoxIcon.Error);
                };
                try { Application.Run(new MainForm()); }
                catch (Exception ex)
                {
                    try { File.WriteAllText(Path.Combine(Application.StartupPath, "RVT_crash.log"), "Startup: " + ex.ToString()); } catch { }
                    MessageBox.Show("Failed to start:\n\n" + ex.ToString(), "RVT System Care Pro", MessageBoxButtons.OK, MessageBoxIcon.Error);
                }
            }
            catch (Exception ex)
            {
                try { File.WriteAllText(Path.Combine(Application.StartupPath, "RVT_fatal.log"), ex.ToString()); } catch { }
            }
        }
    }

