        private string[] GetPatterns()
        {
            string filter = "*.*";
            var ft = cmbFileType.SelectedItem as FTItem;
            if (ft != null)
            {
                if (ft.Pattern == "CUSTOM")
                {
                    filter = txtCustomPattern.Text.Trim();
                    if (filter == "*.rvt;*.rte" || string.IsNullOrWhiteSpace(filter)) return new[] { "*.*" };
                    var parts = filter.Split(';');
                    for (int i = 0; i < parts.Length; i++)
                        if (!parts[i].Trim().StartsWith("*.") && !parts[i].Contains(".")) parts[i] = "*." + parts[i].Trim();
                    return parts.Select(p => p.Trim()).ToArray();
                }
                else return ft.Pattern.Split(';').Select(p => p.Trim()).ToArray();
            }
            return new[] { "*.*" };
        }

        private async void BtnSearch_Click(object sender, EventArgs e)
        {
            if (cts != null) { cts.Cancel(); cts = null; btnSearch.Text = "SEARCH"; return; }
            if (!Directory.Exists(txtPath.Text.Trim())) { MessageBox.Show("Invalid directory.", "Error", MessageBoxButtons.OK, MessageBoxIcon.Warning); return; }
            string[] filters = GetPatterns();
            btnSearch.Text = "STOP"; btnSearch.BackColor = Color.FromArgb(200, 70, 70);
            lblStatus.Text = "Searching..."; progressBar.Visible = true; dgvFiles.DataSource = null;
            fileList = new BindingList<FileItem>(); allResults = new List<FileItem>();
            totalSearched = 0; sw = Stopwatch.StartNew();
            cts = new CancellationTokenSource(); var token = cts.Token;
            try { await Task.Run(() => SearchDir(txtPath.Text.Trim(), filters, chkSubfolders.Checked, token), token); }
            catch (OperationCanceledException) { lblStatus.Text = "Cancelled."; }
            catch (Exception ex) { lblStatus.Text = "Error: " + ex.Message; }
            finally
            {
                sw.Stop(); btnSearch.Text = "SEARCH"; btnSearch.BackColor = Color.FromArgb(70, 120, 220); cts = null;
                progressBar.Visible = false;
                ApplyFilters(); if (allResults.Count > 0) dgvFiles.DataSource = fileList;
                lblCount.Text = string.Format("{0:N0} files", fileList.Count);
                lblTime.Text = string.Format("{0:F2}s", sw.Elapsed.TotalSeconds);
                lblStatus.Text = string.Format("Found {0:N0} files in {1:F2}s", fileList.Count, sw.Elapsed.TotalSeconds);
            }
        }

        private void SearchDir(string dir, string[] filters, bool rec, CancellationToken t)
        {
            var stack = new Stack<string>(); stack.Push(dir);
            while (stack.Count > 0)
            {
                t.ThrowIfCancellationRequested();
                string cur = stack.Pop();
                string[] files = null;
                try { files = Directory.GetFiles(cur); } catch { continue; }
                foreach (string f in files)
                {
                    t.ThrowIfCancellationRequested();
                    bool match = false;
                    foreach (string p in filters)
                    {
                        if (p == "*.*") { match = true; break; }
                        if (p.StartsWith("*.") && f.EndsWith(p.Substring(1), StringComparison.OrdinalIgnoreCase)) { match = true; break; }
                        if (p.StartsWith("*0.") && f.Contains(".0") && f.EndsWith(p.Substring(1), StringComparison.OrdinalIgnoreCase)) { match = true; break; }
                    }
                    if (!match) continue;
                    Interlocked.Increment(ref totalSearched);
                    try { var fi = new FileInfo(f); var item = new FileItem { FullPath = fi.FullName, Name = fi.Name, FolderPath = fi.DirectoryName, Size = fi.Length, SizeDisplay = FormatSize(fi.Length), Type = GetType(fi.Extension), Modified = fi.LastWriteTime, ModifiedDisplay = fi.LastWriteTime.ToString("yyyy-MM-dd HH:mm"), Created = fi.CreationTime, CreatedDisplay = fi.CreationTime.ToString("yyyy-MM-dd HH:mm"), Attributes = fi.Attributes.ToString().Replace(","," | "), Extension = fi.Extension.ToLower() }; lock (allResults) allResults.Add(item); } catch { }
                }
                if (rec) try { foreach (string d in Directory.GetDirectories(cur)) { t.ThrowIfCancellationRequested(); stack.Push(d); } } catch { }
            }
        }

        private void ApplyFilters()
        {
            var q = allResults.AsEnumerable();
            if (chkContains.Checked && !string.IsNullOrWhiteSpace(txtContains.Text)) q = q.Where(f => f.Name.IndexOf(txtContains.Text.Trim(), StringComparison.OrdinalIgnoreCase) >= 0);
            if (chkFirstDigit.Checked && !string.IsNullOrWhiteSpace(txtFirstDigit.Text)) { char d = txtFirstDigit.Text[0]; q = q.Where(f => { foreach (char c in f.Name) if (char.IsDigit(c)) return c == d; return false; }); }
            if (chkFirst5.Checked && !string.IsNullOrWhiteSpace(txtFirst5.Text)) q = q.Where(f => GetFirstN(f.Name,5) == txtFirst5.Text);
            if (chkLastDigit.Checked && !string.IsNullOrWhiteSpace(txtLastDigit.Text)) { char d = txtLastDigit.Text[0]; q = q.Where(f => { for (int i = f.Name.Length-1; i >= 0; i--) if (char.IsDigit(f.Name[i])) return f.Name[i] == d; return false; }); }
            if (chkLast5.Checked && !string.IsNullOrWhiteSpace(txtLast5.Text)) q = q.Where(f => GetLastN(f.Name,5) == txtLast5.Text);
            if (chkSize.Checked) { long mn = 0, mx = long.MaxValue, m = 1; if (cmbSizeUnit.SelectedIndex == 1) m = 1024; else if (cmbSizeUnit.SelectedIndex == 2) m = 1024*1024; else if (cmbSizeUnit.SelectedIndex == 3) m = 1024L*1024*1024; if (!string.IsNullOrWhiteSpace(txtSizeMin.Text)) long.TryParse(txtSizeMin.Text, out mn); if (!string.IsNullOrWhiteSpace(txtSizeMax.Text)) long.TryParse(txtSizeMax.Text, out mx); mn *= m; mx = mx == long.MaxValue ? mx : mx * m; q = q.Where(f => f.Size >= mn && f.Size <= mx); }
            if (chkDate.Checked) { DateTime fr = dtFrom.Value.Date, t = dtTo.Value.Date.AddDays(1); q = q.Where(f => f.Modified >= fr && f.Modified < t); }
            fileList = new BindingList<FileItem>(q.ToList());
        }

        private string GetFirstN(string n, int c) { var sb = new StringBuilder(); foreach (char ch in n) { if (char.IsDigit(ch)) { sb.Append(ch); if (sb.Length >= c) break; } } return sb.ToString(); }
        private string GetLastN(string n, int c) { var sb = new StringBuilder(); for (int i = n.Length-1; i >= 0; i--) { if (char.IsDigit(n[i])) { sb.Insert(0, n[i]); if (sb.Length >= c) break; } } return sb.ToString(); }

        private void ClearResults() { dgvFiles.DataSource = null; fileList = null; allResults = null; totalSearched = 0; lblStatus.Text = "Ready"; dgvFiles.Refresh(); GC.Collect(); }

        private void OpenFiles() { if (dgvFiles.SelectedRows.Count == 0) return; foreach (DataGridViewRow r in dgvFiles.SelectedRows) { var fi = r.DataBoundItem as FileItem; if (fi != null) try { Process.Start(fi.FullPath); } catch { } } }
        private void OpenLocation() { if (dgvFiles.SelectedRows.Count == 0) return; var fi = dgvFiles.SelectedRows[0].DataBoundItem as FileItem; if (fi != null) try { Process.Start("explorer.exe", "/select,\"" + fi.FullPath + "\""); } catch { } }
        private void RenameFile() { if (dgvFiles.SelectedRows.Count != 1) return; var fi = dgvFiles.SelectedRows[0].DataBoundItem as FileItem; if (fi == null) return; string nn = Interaction.InputBox("New name:", "Rename", fi.Name); if (!string.IsNullOrWhiteSpace(nn) && nn != fi.Name) { try { string np = Path.Combine(Path.GetDirectoryName(fi.FullPath), nn); if (File.Exists(np)) { MessageBox.Show("Already exists.","Error",MessageBoxButtons.OK,MessageBoxIcon.Warning); return; } File.Move(fi.FullPath, np); fi.Name = nn; fi.FullPath = np; dgvFiles.Refresh(); } catch (Exception ex) { MessageBox.Show("Error: " + ex.Message, "Error", MessageBoxButtons.OK, MessageBoxIcon.Error); } } }
        private void DeleteFiles() { if (dgvFiles.SelectedRows.Count == 0) return; if (MessageBox.Show("Delete " + dgvFiles.SelectedRows.Count + " file(s)?", "Confirm", MessageBoxButtons.YesNo, MessageBoxIcon.Warning) != DialogResult.Yes) return; int d = 0, f = 0; foreach (DataGridViewRow r in dgvFiles.SelectedRows) { var fi = r.DataBoundItem as FileItem; if (fi != null) { try { File.Delete(fi.FullPath); fileList.Remove(fi); d++; } catch { f++; } } } lblStatus.Text = "Deleted: " + d + " Failed: " + f; }
        private void CopyPath() { if (dgvFiles.SelectedRows.Count == 0) return; var sb = new StringBuilder(); foreach (DataGridViewRow r in dgvFiles.SelectedRows) { var fi = r.DataBoundItem as FileItem; if (fi != null) sb.AppendLine(fi.FullPath); } if (sb.Length > 0) Clipboard.SetText(sb.ToString().TrimEnd()); }
        private void ShowProps() { if (dgvFiles.SelectedRows.Count == 0) return; var fp = dgvFiles.SelectedRows[0].DataBoundItem as FileItem; if (fp == null) return; try { var info = new FileInfo(fp.FullPath); MessageBox.Show(string.Format("Name: {0}\nPath: {1}\n\nSize: {2} ({3:N0} bytes)\nType: {4}\n\nCreated: {5}\nModified: {6}\nAccessed: {7}\n\nAttributes: {8}", info.Name, info.FullName, FormatSize(info.Length), info.Length, GetType(info.Extension), info.CreationTime.ToString("yyyy-MM-dd HH:mm"), info.LastWriteTime.ToString("yyyy-MM-dd HH:mm"), info.LastAccessTime.ToString("yyyy-MM-dd HH:mm"), info.Attributes), "Properties", MessageBoxButtons.OK, MessageBoxIcon.Information); } catch { } }

