        private async void BtnClean_Click(object sender, EventArgs e)
        {
            if (clbDriveItems.CheckedItems.Count == 0) { MessageBox.Show("Select items.", "Drive Cleaner"); return; }
            if (MessageBox.Show("Clean selected items? This may delete files permanently.", "Confirm", MessageBoxButtons.YesNo, MessageBoxIcon.Warning) != DialogResult.Yes) return;

            btnClean.Enabled = false; pbDrive.Visible = true; pbDrive.Maximum = clbDriveItems.CheckedItems.Count; pbDrive.Value = 0;
            rtbDriveLog.Clear(); rtbDriveLog.AppendText("=== Cleaning in progress ===\n\n");
            int cur = 0;

            foreach (string item in clbDriveItems.CheckedItems)
            {
                cur++; pbDrive.Value = cur;
                rtbDriveLog.AppendText(string.Format("[{0}/{1}] {2}...", cur, pbDrive.Maximum, item) + "\n");
                rtbDriveLog.ScrollToCaret();
                await Task.Run(() =>
                {
                    try
                    {
                        if (item.StartsWith("Windows Temp")) CleanDir(Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.Windows), "Temp"), true);
                        else if (item.StartsWith("User Temp")) CleanDir(Path.GetTempPath(), false);
                        else if (item.StartsWith("Recycle Bin")) { SHEmptyRecycleBinW(IntPtr.Zero, null, 0); }
                        else if (item.StartsWith("Prefetch")) CleanDir(Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.Windows), "Prefetch"), true);
                        else if (item.StartsWith("Recent Documents")) CleanDir(Environment.GetFolderPath(Environment.SpecialFolder.Recent), false);
                        else if (item.StartsWith("Thumbnail")) CleanThumbCache();
                        else if (item.StartsWith("DNS")) Process.Start(new ProcessStartInfo("ipconfig", "/flushdns") { CreateNoWindow = true, WindowStyle = ProcessWindowStyle.Hidden }).WaitForExit(5000);
                        else if (item.StartsWith("Chrome")) CleanBrowser("Chrome");
                        else if (item.StartsWith("Firefox")) CleanBrowser("Firefox");
                        else if (item.StartsWith("Edge")) CleanBrowser("Edge");
                        else if (item.StartsWith("Windows Error")) CleanDir(Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData), "Microsoft", "Windows", "WER"), true);
                        else if (item.StartsWith("Delivery")) CleanDir(Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.Windows), "SoftwareDistribution", "DeliveryOptimization"), true);
                        else if (item.StartsWith("Windows Update")) CleanDir(Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.Windows), "SoftwareDistribution", "Download"), true);
                        else if (item.StartsWith("Memory Dump")) CleanDir(Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.Windows), "Minidump"), true);
                        else if (item.StartsWith("Old Windows")) { var w = Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.Windows), "WinSxS", "Backup"); if (Directory.Exists(w)) CleanDir(w, true); }
                        else if (item.StartsWith("Browser History")) { } // Placeholder
                        else if (item.StartsWith("Cookie")) { } // Placeholder
                        else if (item.StartsWith("Downloaded Program")) CleanDir(Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.Windows), "Downloaded Program Files"), true);
                        rtbDriveLog.Invoke((MethodInvoker)delegate { rtbDriveLog.AppendText(string.Format("  -> {0} complete\n", item)); rtbDriveLog.ScrollToCaret(); });
                    }
                    catch (Exception ex) { rtbDriveLog.Invoke((MethodInvoker)delegate { rtbDriveLog.AppendText(string.Format("  -> Error: {0}\n", ex.Message)); }); }
                });
            }
            rtbDriveLog.AppendText("\n=== Cleaning finished! ===\n"); rtbDriveLog.ScrollToCaret();
            pbDrive.Visible = false; btnClean.Enabled = true;
        }

        private void CleanDir(string dir, bool rec)
        {
            if (!Directory.Exists(dir)) return;
            foreach (string f in Directory.GetFiles(dir)) try { File.Delete(f); } catch { }
            if (rec) foreach (string d in Directory.GetDirectories(dir)) try { Directory.Delete(d, true); } catch { }
        }

        private void CleanThumbCache()
        {
            string dir = Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData), "Microsoft", "Windows", "Explorer");
            if (Directory.Exists(dir)) foreach (string f in Directory.GetFiles(dir, "thumbcache_*")) try { File.Delete(f); } catch { }
        }

        private void CleanBrowser(string name)
        {
            string local = Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData);
            string dir = "";
            if (name == "Chrome") dir = Path.Combine(local, "Google", "Chrome", "User Data", "Default", "Cache");
            else if (name == "Firefox") dir = Path.Combine(local, "Mozilla", "Firefox", "Profiles");
            else if (name == "Edge") dir = Path.Combine(local, "Microsoft", "Edge", "User Data", "Default", "Cache");
            if (Directory.Exists(dir)) CleanDir(dir, true);
        }

