        private void UpdateMemInfo()
        {
            try
            {
                using (var s = new ManagementObjectSearcher("SELECT * FROM Win32_OperatingSystem"))
                {
                    foreach (ManagementObject o in s.Get())
                    {
                        double total = Convert.ToDouble(o["TotalVisibleMemorySize"]) / 1024;
                        double free = Convert.ToDouble(o["FreePhysicalMemory"]) / 1024;
                        double used = total - free;
                        int pct = (int)(used / total * 100);
                        double page = Convert.ToDouble(o["TotalVirtualMemorySize"]) / 1024;
                        lblPhysMem.Text = string.Format("Physical: {0:F1} GB", total / 1024);
                        lblAvailMem.Text = string.Format("Available: {0:F0} MB", free);
                        lblUsedMem.Text = string.Format("Used: {0:F0} MB", used);
                        lblMemPercent.Text = string.Format("Usage: {0}%", pct);
                        lblPageFile.Text = string.Format("Page: {0:F1} GB", page / 1024);

                        Panel fill = memInfoPanel.Controls["usageFill"] as Panel;
                        if (fill != null) { fill.Width = (int)((double)pct / 100 * 378); fill.BackColor = pct > 80 ? Color.FromArgb(200, 70, 70) : pct > 60 ? Color.FromArgb(220, 160, 50) : Color.FromArgb(80, 160, 80); }

                    memGraph.AddDataPoint(pct);
                        memGraph.Invalidate();
                        lblMem.Text = string.Format("Mem: {0}%", pct);
                    }
                }
            }
            catch { }
        }

        private void CleanMem()
        {
            try
            {
                GC.Collect(); GC.WaitForPendingFinalizers();
                SetProcessWorkingSetSize(Process.GetCurrentProcess().Handle, (IntPtr)(-1), (IntPtr)(-1));
                foreach (Process p in Process.GetProcesses()) try { if (p.Id != Process.GetCurrentProcess().Id && !string.IsNullOrEmpty(p.MainWindowTitle)) SetProcessWorkingSetSize(p.Handle, (IntPtr)(-1), (IntPtr)(-1)); } catch { }
                UpdateMemInfo();
                MessageBox.Show("Memory cleaned!\n\nGC + Working Set Trim + Cache Clear completed.", "Memory Optimizer", MessageBoxButtons.OK, MessageBoxIcon.Information);
            }
            catch (Exception ex) { MessageBox.Show("Error: " + ex.Message, "Error", MessageBoxButtons.OK, MessageBoxIcon.Error); }
        }

        private void TrimWS()
        {
            try
            {
                GC.Collect(); GC.WaitForPendingFinalizers();
                SetProcessWorkingSetSize(Process.GetCurrentProcess().Handle, (IntPtr)(-1), (IntPtr)(-1));
                UpdateMemInfo();
                MessageBox.Show("Working set trimmed!", "Memory Optimizer", MessageBoxButtons.OK, MessageBoxIcon.Information);
            }
            catch (Exception ex) { MessageBox.Show("Error: " + ex.Message, "Error", MessageBoxButtons.OK, MessageBoxIcon.Error); }
        }

        [DllImport("kernel32.dll")]
        private static extern bool SetProcessWorkingSetSize(IntPtr proc, IntPtr min, IntPtr max);

        // ========== REGISTRY TOOLS ==========

        private void BuildRegistry()
        {
            var tlp = new TableLayoutPanel { Dock = DockStyle.Fill, ColumnCount = 2, RowCount = 3, Padding = new Padding(8) };
            tlp.RowStyles.Add(new RowStyle(SizeType.Absolute, 28));
            tlp.RowStyles.Add(new RowStyle(SizeType.Percent, 40));
            tlp.RowStyles.Add(new RowStyle(SizeType.Percent, 60));
            tlp.ColumnStyles.Add(new ColumnStyle(SizeType.Absolute, 320));
            tlp.ColumnStyles.Add(new ColumnStyle(SizeType.Percent, 100));

            var lblReg = new Label { Text = "Registry Scanner & Editor", Font = new Font("Segoe UI", 9.5f, FontStyle.Bold), ForeColor = Color.FromArgb(40, 40, 60) };
            tlp.Controls.Add(lblReg, 0, 0); tlp.SetColumnSpan(lblReg, 2);

            // Registry tree
            tvRegistry = new TreeView { Dock = DockStyle.Fill, BorderStyle = BorderStyle.FixedSingle, BackColor = Color.White, Font = new Font("Segoe UI", 9f) };
            tvRegistry.Nodes.Add("HKEY_CLASSES_ROOT");
            tvRegistry.Nodes.Add("HKEY_CURRENT_USER");
            tvRegistry.Nodes.Add("HKEY_LOCAL_MACHINE");
            tvRegistry.Nodes.Add("HKEY_USERS");
            tvRegistry.Nodes.Add("HKEY_CURRENT_CONFIG");
            tvRegistry.AfterSelect += TvRegistry_AfterSelect;
            var cmsRegTree = new ContextMenuStrip();
            cmsRegTree.Items.Add("New Key", null, (s, e) => NewRegistryKey());
