        private void TvRegistry_AfterSelect(object sender, TreeViewEventArgs e)
        {
            lvRegValues.Items.Clear();
            string path = GetRegPath(e.Node);
            if (string.IsNullOrEmpty(path)) return;
            try
            {
                string subPath = null;
                RegistryKey root = GetRootKey(path, out subPath);
                if (root == null) return;
                using (RegistryKey key = root.OpenSubKey(subPath))
                {
                    if (key == null) { root.Dispose(); return; }
                    foreach (string val in key.GetValueNames())
                    {
                        var lvi = new ListViewItem(string.IsNullOrEmpty(val) ? "(Default)" : val);
                        object data = key.GetValue(val);
                        lvi.SubItems.Add(data is string[] ? "MULTI_SZ" : data is byte[] ? "BINARY" : data is int ? "DWORD" : data is long ? "QWORD" : "SZ");
                        lvi.SubItems.Add(data is string[] ? string.Join(",", (string[])data) : data is byte[] ? (data as byte[]).Length + " bytes" : data.ToString());
                        lvRegValues.Items.Add(lvi);
                    }
                    key.Close();
                }
                root.Dispose();

                // Load subkeys
                e.Node.Nodes.Clear();
                string subPath2 = null;
                RegistryKey root2 = GetRootKey(path, out subPath2);
                if (root2 != null)
                {
                    using (RegistryKey key = root2.OpenSubKey(subPath2))
                    {
                        if (key != null)
                        {
                            foreach (string sub in key.GetSubKeyNames())
                            {
                                var tn = new TreeNode(sub);
                                try { using (RegistryKey sk = key.OpenSubKey(sub)) { if (sk != null && sk.SubKeyCount > 0) tn.Nodes.Add("..."); sk.Close(); } } catch { }
                                e.Node.Nodes.Add(tn);
                            }
                            key.Close();
                        }
                    }
                    root2.Dispose();
                }
            }
            catch { }
        }

        private string GetRegPath(TreeNode node)
        {
            var path = new List<string>();
            TreeNode n = node;
            while (n != null) { path.Insert(0, n.Text); n = n.Parent; }
            return string.Join("\\", path);
        }

        private RegistryKey GetRootKey(string fullPath, out string subPath)
        {
            subPath = "";
            if (fullPath.StartsWith("HKEY_CLASSES_ROOT")) { subPath = fullPath.Substring(19).TrimStart('\\'); return Registry.ClassesRoot; }
            if (fullPath.StartsWith("HKEY_CURRENT_USER")) { subPath = fullPath.Substring(18).TrimStart('\\'); return Registry.CurrentUser; }
            if (fullPath.StartsWith("HKEY_LOCAL_MACHINE")) { subPath = fullPath.Substring(19).TrimStart('\\'); return Registry.LocalMachine; }
            if (fullPath.StartsWith("HKEY_USERS")) { subPath = fullPath.Substring(10).TrimStart('\\'); return Registry.Users; }
            if (fullPath.StartsWith("HKEY_CURRENT_CONFIG")) { subPath = fullPath.Substring(20).TrimStart('\\'); return Registry.CurrentConfig; }
            return null;
        }

        private async void BtnRegScan_Click(object sender, EventArgs e)
        {
            lvRegIssues.Items.Clear(); regIssues.Clear();
            pbReg.Visible = true; lblRegStatus.Text = "Scanning...";
            btnRegScan.Enabled = false; btnRegFix.Enabled = false;
            await Task.Run(() =>
            {
                ScanRecentDocMRU(); ScanRunMRU(); ScanEmptyExt(); ScanInvalidUninst(); ScanUserAssist(); ScanTypedURLs(); ScanEmptyCLSID();
            });
            foreach (var issue in regIssues)
            {
                var lvi = new ListViewItem(issue.Issue);
                lvi.SubItems.Add(issue.Path); lvi.SubItems.Add(issue.Data); lvi.Tag = issue;
                lvRegIssues.Items.Add(lvi);
            }
            pbReg.Visible = false; btnRegScan.Enabled = true; btnRegFix.Enabled = true;
            lblRegStatus.Text = string.Format("Found {0} issues", regIssues.Count);
        }

        private void BtnRegFix_Click(object sender, EventArgs e)
        {
            if (lvRegIssues.SelectedItems.Count == 0) return;
            if (MessageBox.Show("Fix selected issues? Backup recommended.", "Registry", MessageBoxButtons.YesNo, MessageBoxIcon.Warning) != DialogResult.Yes) return;
            int fixedCount = 0;
            foreach (ListViewItem item in lvRegIssues.SelectedItems)
            {
                var issue = item.Tag as RegIssue;
                if (issue == null) continue;
                try
                {
                    string path = issue.Path;
                    if (path.StartsWith("HKCU\\")) path = path.Substring(5);
                    else if (path.StartsWith("HKLM\\")) { /* skip HKLM for safety */ continue; }
                    else if (path.StartsWith("HKCR\\")) { /* skip HKCR for safety */ continue; }
                    else continue;
                    int lastSlash = path.LastIndexOf('\\');
                    if (lastSlash < 0) continue;
                    string parent = path.Substring(0, lastSlash);
                    string name = path.Substring(lastSlash + 1);
                    using (RegistryKey key = Registry.CurrentUser.OpenSubKey(parent, true))
                    {
                        if (key != null) { key.DeleteValue(name, false); key.Close(); fixedCount++; }
                    }
                }
                catch { }
            }
            lblRegStatus.Text = string.Format("Fixed {0} issues", fixedCount);
        }

        private void ScanRecentDocMRU()
        {
            using (var key = Registry.CurrentUser.OpenSubKey(@"Software\Microsoft\Windows\CurrentVersion\Explorer\RecentDocs"))
            {
                if (key != null) { int count = key.ValueCount; if (count > 0) regIssues.Add(new RegIssue { Issue = "Recent Documents MRU", Path = @"HKCU\Software\Microsoft\Windows\CurrentVersion\Explorer\RecentDocs", Data = count + " entries", IsKey = false }); key.Close(); }
            }
        }

        private void ScanRunMRU()
        {
            using (var key = Registry.CurrentUser.OpenSubKey(@"Software\Microsoft\Windows\CurrentVersion\Explorer\RunMRU"))
            {
                if (key != null) { int count = key.ValueCount; if (count > 0) regIssues.Add(new RegIssue { Issue = "Run MRU History", Path = @"HKCU\Software\Microsoft\Windows\CurrentVersion\Explorer\RunMRU", Data = count + " entries", IsKey = false }); key.Close(); }
            }
        }

        private void ScanEmptyExt()
        {
            using (var key = Registry.ClassesRoot.OpenSubKey(""))
            {
                if (key != null) { int count = 0; foreach (string s in key.GetSubKeyNames()) { if (s.StartsWith(".")) { using (var ek = key.OpenSubKey(s)) { if (ek != null) { string def = ek.GetValue("", "") as string; if (string.IsNullOrEmpty(def) && ek.SubKeyCount == 0) count++; ek.Close(); } } } } if (count > 0) regIssues.Add(new RegIssue { Issue = "Empty File Extensions", Path = "HKCR\\.", Data = count + " extensions" }); key.Close(); }
            }
        }

        private void ScanInvalidUninst()
        {
            using (var key = Registry.LocalMachine.OpenSubKey(@"Software\Microsoft\Windows\CurrentVersion\Uninstall"))
            {
                if (key != null) { int count = 0; foreach (string s in key.GetSubKeyNames()) { using (var ak = key.OpenSubKey(s)) { if (ak != null) { string dn = ak.GetValue("DisplayName", "") as string; string us = ak.GetValue("UninstallString", "") as string; if (!string.IsNullOrEmpty(dn) && string.IsNullOrEmpty(us)) count++; ak.Close(); } } } if (count > 0) regIssues.Add(new RegIssue { Issue = "Invalid Uninstall Entries", Path = @"HKLM\Software\Microsoft\Windows\CurrentVersion\Uninstall", Data = count + " entries" }); key.Close(); }
            }
        }

        private void ScanUserAssist()
        {
            using (var key = Registry.CurrentUser.OpenSubKey(@"Software\Microsoft\Windows\CurrentVersion\Explorer\UserAssist"))
            {
                if (key != null) { int count = 0; foreach (string s in key.GetSubKeyNames()) { RegistryKey gk = null; try { gk = key.OpenSubKey(s + @"\Count"); if (gk != null) count += gk.ValueCount; } finally { if (gk != null) gk.Close(); } } if (count > 0) regIssues.Add(new RegIssue { Issue = "UserAssist Tracking", Path = @"HKCU\Software\Microsoft\Windows\CurrentVersion\Explorer\UserAssist", Data = count + " entries" }); key.Close(); }
            }
        }

        private void ScanTypedURLs()
        {
            using (var key = Registry.CurrentUser.OpenSubKey(@"Software\Microsoft\Internet Explorer\TypedURLs"))
            {
                if (key != null) { int count = key.ValueCount; if (count > 0) regIssues.Add(new RegIssue { Issue = "Typed URLs History", Path = @"HKCU\Software\Microsoft\Internet Explorer\TypedURLs", Data = count + " entries" }); key.Close(); }
            }
        }

        private void ScanEmptyCLSID()
        {
            using (var key = Registry.ClassesRoot.OpenSubKey("CLSID"))
            {
                if (key != null) { int count = 0; foreach (string s in key.GetSubKeyNames()) { using (var ck = key.OpenSubKey(s)) { if (ck != null) { if (string.IsNullOrEmpty(ck.GetValue("", "") as string)) count++; ck.Close(); } } } if (count > 0) regIssues.Add(new RegIssue { Issue = "Empty CLSID Keys", Path = @"HKCR\CLSID", Data = count + " empty keys" }); key.Close(); }
            }
        }

        private void BackupRegistry()
        {
            using (var dlg = new SaveFileDialog { Filter = "REG files (*.reg)|*.reg", FileName = "registry_backup_" + DateTime.Now.ToString("yyyyMMdd") + ".reg" })
            {
                if (dlg.ShowDialog() == DialogResult.OK)
                {
                    try
                    {
                        Process.Start("regedit.exe", "/e \"" + dlg.FileName + "\"");
                        MessageBox.Show("Registry backup started.\n\nFile: " + dlg.FileName, "Backup", MessageBoxButtons.OK, MessageBoxIcon.Information);
                    }
                    catch (Exception ex) { MessageBox.Show("Error: " + ex.Message, "Error", MessageBoxButtons.OK, MessageBoxIcon.Error); }
                }
            }
        }

        private void RestoreRegistry()
        {
            using (var dlg = new OpenFileDialog { Filter = "REG files (*.reg)|*.reg" })
            {
                if (dlg.ShowDialog() == DialogResult.OK)
                {
                    if (MessageBox.Show("Restore registry from " + dlg.FileName + "?", "Confirm", MessageBoxButtons.YesNo, MessageBoxIcon.Warning) == DialogResult.Yes)
                    {
                        try { Process.Start("regedit.exe", "\"" + dlg.FileName + "\""); MessageBox.Show("Registry import started.", "Restore", MessageBoxButtons.OK, MessageBoxIcon.Information); }
                        catch (Exception ex) { MessageBox.Show("Error: " + ex.Message, "Error", MessageBoxButtons.OK, MessageBoxIcon.Error); }
                    }
                }
            }
        }

        private void ExportRegistry()
        {
            if (tvRegistry.SelectedNode == null) { MessageBox.Show("Select a registry key first.", "Export", MessageBoxButtons.OK, MessageBoxIcon.Information); return; }
            string path = GetRegPath(tvRegistry.SelectedNode);
            using (var dlg = new SaveFileDialog { Filter = "REG files (*.reg)|*.reg", FileName = tvRegistry.SelectedNode.Text + ".reg" })
            {
                if (dlg.ShowDialog() == DialogResult.OK)
                {
                    try { Process.Start("regedit.exe", "/e \"" + dlg.FileName + "\" \"" + path + "\""); MessageBox.Show("Export started: " + path, "Export", MessageBoxButtons.OK, MessageBoxIcon.Information); }
                    catch (Exception ex) { MessageBox.Show("Error: " + ex.Message, "Error", MessageBoxButtons.OK, MessageBoxIcon.Error); }
                }
            }
        }

