        private void LoadDrivers()
        {
            lvDrivers.Items.Clear(); lblDriverCount.Text = "Loading...";
            try
            {
                using (var searcher = new ManagementObjectSearcher("SELECT * FROM Win32_SystemDriver"))
                {
                    foreach (ManagementObject obj in searcher.Get())
                    {
                        var lvi = new ListViewItem(GetStr(obj["Name"]));
                        lvi.SubItems.Add(GetStr(obj["DisplayName"]));
                        lvi.SubItems.Add(GetStr(obj["Status"]));
                        lvi.SubItems.Add(GetStr(obj["State"]));
                        lvi.SubItems.Add(GetStr(obj["StartMode"]));
                        lvi.SubItems.Add(GetStr(obj["ServiceType"]));
                        lvi.SubItems.Add(GetStr(obj["PathName"]));
                        lvi.SubItems.Add(GetStr(obj["Description"]));
                        lvDrivers.Items.Add(lvi);
                    }
                }
                lblDriverCount.Text = string.Format("Total: {0} drivers", lvDrivers.Items.Count);
            }
            catch (Exception ex) { lblDriverCount.Text = "Error: " + ex.Message; }
        }

        private string GetStr(object o) { return o != null ? o.ToString().Trim() : "-"; }

