        private DateTime CalcNextRun(int interval, int unit)
        {
            DateTime now = DateTime.Now;
            switch (unit)
            {
                case 0: return now.AddMinutes(interval);
                case 1: return now.AddHours(interval);
                case 2: return now.AddDays(interval);
                case 3: return now.AddDays(interval * 7);
                default: return now.AddDays(1);
            }
        }

        private void CheckSchedule()
        {
            foreach (ListViewItem item in lvTasks.Items)
            {
                var task = item.Tag as SchedTask;
                if (task == null || !task.Enabled) continue;
                if (DateTime.Now >= task.NextRun)
                {
                    RunTask(task, item);
                    task.NextRun = CalcNextRun(task.Interval, task.Unit);
                    item.SubItems[5].Text = task.NextRun.ToString("yyyy-MM-dd HH:mm");
                    item.SubItems[4].Text = DateTime.Now.ToString("yyyy-MM-dd HH:mm");
                    SaveSchedule();
                }
            }
        }

        private void RunSchedTask()
        {
            if (lvTasks.SelectedItems.Count == 0) return;
            var task = lvTasks.SelectedItems[0].Tag as SchedTask;
            if (task == null) return;
            RunTask(task, lvTasks.SelectedItems[0]);
            task.NextRun = CalcNextRun(task.Interval, task.Unit);
            lvTasks.SelectedItems[0].SubItems[5].Text = task.NextRun.ToString("yyyy-MM-dd HH:mm");
            SaveSchedule();
        }

        private void RunTask(SchedTask task, ListViewItem item)
        {
            try
            {
                if (task.Action.Contains("Temp")) { }
                else if (task.Action.Contains("Memory")) { GC.Collect(); SetProcessWorkingSetSize(Process.GetCurrentProcess().Handle, (IntPtr)(-1), (IntPtr)(-1)); }
                else if (task.Action.Contains("Registry")) { }
                else { CleanDir(Path.GetTempPath(), false); CleanDir(Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.Windows), "Temp"), true); }
                item.SubItems[4].Text = DateTime.Now.ToString("yyyy-MM-dd HH:mm");
                lblStatus.Text = "Scheduled task executed: " + task.Name;
            }
            catch { }
        }

        private void SaveSchedule()
        {
            try
            {
                var sb = new StringBuilder();
                foreach (ListViewItem item in lvTasks.Items)
                {
                    var t = item.Tag as SchedTask;
                    if (t != null) sb.AppendLine(string.Format("{0}|{1}|{2}|{3}|{4}|{5}", t.Name, t.Action, t.Interval, t.Unit, t.Enabled, t.NextRun.ToString("O")));
                }
                File.WriteAllText(schedConfigPath, sb.ToString());
            }
            catch { }
        }

        private void LoadSchedule()
        {
            try
            {
                if (!File.Exists(schedConfigPath)) return;
                foreach (string line in File.ReadAllLines(schedConfigPath))
                {
                    if (string.IsNullOrWhiteSpace(line)) continue;
                    string[] parts = line.Split('|');
                    if (parts.Length >= 6)
                    {
                        var task = new SchedTask { Name = parts[0], Action = parts[1], Interval = int.Parse(parts[2]), Unit = int.Parse(parts[3]), Enabled = bool.Parse(parts[4]), NextRun = DateTime.Parse(parts[5]) };
                        var lvi = new ListViewItem(task.Name);
                        lvi.SubItems.Add(task.Action);
                        lvi.SubItems.Add(task.Interval + " " + (new[] { "Minutes", "Hours", "Days", "Weeks" })[task.Unit]);
                        lvi.SubItems.Add(task.Enabled ? "Yes" : "No");
                        lvi.SubItems.Add("Unknown");
                        lvi.SubItems.Add(task.NextRun.ToString("yyyy-MM-dd HH:mm"));
                        lvi.Tag = task;
                        lvTasks.Items.Add(lvi);
                    }
                }
                UpdateSchedTimer();
            }
            catch { }
        }

        private void UpdateSchedTimer()
        {
            if (lvTasks.Items.Count > 0) { if (!schedTimer.Enabled) schedTimer.Start(); }
            else schedTimer.Stop();
        }

