        private string FormatSize(long bytes)
        {
            if (bytes < 1024) return bytes + " B";
            if (bytes < 1024 * 1024) return (bytes / 1024.0).ToString("F1") + " KB";
            if (bytes < 1024L * 1024 * 1024) return (bytes / (1024.0 * 1024)).ToString("F1") + " MB";
            return (bytes / (1024.0 * 1024 * 1024)).ToString("F2") + " GB";
        }

        private string GetType(string ext)
        {
            switch (ext.ToLower())
            {
                case ".rvt": return "Revit";
                case ".rte": return "Revit Tpl";
                case ".rfa": return "Revit Fam";
                case ".txt": case ".pdf": case ".doc": case ".docx": case ".xls": case ".xlsx": return "Doc";
                case ".jpg": case ".jpeg": case ".png": case ".gif": case ".bmp": return "Image";
                case ".mp3": case ".wav": case ".flac": return "Audio";
                case ".mp4": case ".avi": case ".mkv": case ".mov": return "Video";
                case ".zip": case ".rar": case ".7z": return "Archive";
                case ".exe": return "App";
                case ".cs": case ".js": case ".py": case ".html": case ".json": case ".xml": return "Code";
                case ".dll": return "DLL";
                case ".lnk": return "Shortcut";
                default: return ext.ToUpper().Replace(".", "") + " File";
            }
        }

