        private void NewRegistryKey()
        {
            if (tvRegistry.SelectedNode == null) { MessageBox.Show("Select a parent key first.", "New Key", MessageBoxButtons.OK, MessageBoxIcon.Information); return; }
            string name = Interaction.InputBox("Enter new key name:", "New Registry Key", "New Key #1");
            if (string.IsNullOrWhiteSpace(name)) return;
            string parentPath = GetRegPath(tvRegistry.SelectedNode);
            RegistryKey root = null; string subPath = null;
            try
            {
                root = GetRootKey(parentPath, out subPath);
                if (root != null)
                {
                    using (RegistryKey parent = (string.IsNullOrEmpty(subPath) ? root : root.OpenSubKey(subPath, true)))
                    {
                        if (parent != null) { parent.CreateSubKey(name); parent.Close(); }
                        MessageBox.Show("Key created: " + parentPath + "\\" + name, "Success", MessageBoxButtons.OK, MessageBoxIcon.Information);
                        TvRegistry_AfterSelect(tvRegistry.SelectedNode.Parent != null ? tvRegistry.SelectedNode.Parent : tvRegistry.SelectedNode, null);
                    }
                }
            }
            catch (Exception ex) { MessageBox.Show("Error creating key: " + ex.Message, "Error", MessageBoxButtons.OK, MessageBoxIcon.Error); }
            finally { if (root != null) root.Dispose(); }
        }

