        private void ModifyRegistryValue()
        {
            if (tvRegistry.SelectedNode == null || lvRegValues.SelectedItems.Count == 0)
            { MessageBox.Show("Select a registry value first.", "Modify", MessageBoxButtons.OK, MessageBoxIcon.Information); return; }
            string valName = lvRegValues.SelectedItems[0].Text;
            string valType = lvRegValues.SelectedItems[0].SubItems[1].Text;
            string valData = lvRegValues.SelectedItems[0].SubItems[2].Text;
            string path = GetRegPath(tvRegistry.SelectedNode);
            RegistryKey root = null; string subPath = null;
            try
            {
                root = GetRootKey(path, out subPath);
                if (root != null)
                {
                    using (RegistryKey key = (string.IsNullOrEmpty(subPath) ? root : root.OpenSubKey(subPath, true)))
                    {
                        if (key == null) return;
                        string newData = Interaction.InputBox("Modify value (" + valType + "):\n" + valName, "Modify Value", valData);
                        if (newData == null) { key.Close(); return; }
                        if (valType == "DWORD") { uint d; if (uint.TryParse(newData, out d)) key.SetValue(valName == "(Default)" ? "" : valName, (int)d, RegistryValueKind.DWord); }
                        else if (valType == "QWORD") { long q; if (long.TryParse(newData, out q)) key.SetValue(valName == "(Default)" ? "" : valName, q, RegistryValueKind.QWord); }
                        else key.SetValue(valName == "(Default)" ? "" : valName, newData);
                        key.Close();
                        TvRegistry_AfterSelect(tvRegistry.SelectedNode, null);
                    }
                }
            }
            catch (Exception ex) { MessageBox.Show("Error: " + ex.Message, "Error", MessageBoxButtons.OK, MessageBoxIcon.Error); }
            finally { if (root != null) root.Dispose(); }
        }

        private void DeleteRegistryItem()
        {
            if (tvRegistry.SelectedNode == null) { MessageBox.Show("Select a key or value first.", "Delete", MessageBoxButtons.OK, MessageBoxIcon.Information); return; }
            if (lvRegValues.SelectedItems.Count > 0)
            {
                string valName = lvRegValues.SelectedItems[0].Text;
                if (MessageBox.Show("Delete value '" + valName + "'?", "Confirm Delete", MessageBoxButtons.YesNo, MessageBoxIcon.Warning) != DialogResult.Yes) return;
                string path = GetRegPath(tvRegistry.SelectedNode);
                RegistryKey root = null; string subPath = null;
                try
                {
                    root = GetRootKey(path, out subPath);
                    if (root != null)
                    {
                        using (RegistryKey key = (string.IsNullOrEmpty(subPath) ? root : root.OpenSubKey(subPath, true)))
                        {
                            if (key != null) { key.DeleteValue(valName == "(Default)" ? "" : valName, false); key.Close(); }
                            TvRegistry_AfterSelect(tvRegistry.SelectedNode, null);
                        }
                    }
                }
                catch (Exception ex) { MessageBox.Show("Error: " + ex.Message, "Error", MessageBoxButtons.OK, MessageBoxIcon.Error); }
                finally { if (root != null) root.Dispose(); }
            }
            else
            {
                string keyPath = GetRegPath(tvRegistry.SelectedNode);
                if (tvRegistry.SelectedNode.Parent == null) { MessageBox.Show("Cannot delete root keys.", "Error", MessageBoxButtons.OK, MessageBoxIcon.Warning); return; }
                if (MessageBox.Show("Delete key '" + keyPath + "' and all subkeys?", "Confirm Delete", MessageBoxButtons.YesNo, MessageBoxIcon.Warning) != DialogResult.Yes) return;
                string parentPath = GetRegPath(tvRegistry.SelectedNode.Parent);
                string keyName = tvRegistry.SelectedNode.Text;
                RegistryKey root = null; string subPath = null;
                try
                {
                    root = GetRootKey(parentPath, out subPath);
                    if (root != null)
                    {
                        using (RegistryKey parent = (string.IsNullOrEmpty(subPath) ? root : root.OpenSubKey(subPath, true)))
                        {
                            if (parent != null) { parent.DeleteSubKeyTree(keyName); parent.Close(); }
                            TreeNode p = tvRegistry.SelectedNode.Parent;
                            tvRegistry.SelectedNode = p;
                            if (p != null) TvRegistry_AfterSelect(p, null);
                        }
                    }
                }
                catch (Exception ex) { MessageBox.Show("Error: " + ex.Message, "Error", MessageBoxButtons.OK, MessageBoxIcon.Error); }
                finally { if (root != null) root.Dispose(); }
            }
        }

        private void RenameRegistryItem()
        {
            if (tvRegistry.SelectedNode == null) { MessageBox.Show("Select a key or value first.", "Rename", MessageBoxButtons.OK, MessageBoxIcon.Information); return; }
            if (lvRegValues.SelectedItems.Count > 0)
            {
                string oldName = lvRegValues.SelectedItems[0].Text;
                string newName = Interaction.InputBox("Rename value:", "Rename Value", oldName);
                if (string.IsNullOrWhiteSpace(newName) || newName == oldName) return;
                string path = GetRegPath(tvRegistry.SelectedNode);
                RegistryKey root = null; string subPath = null;
                try
                {
                    root = GetRootKey(path, out subPath);
                    if (root != null)
                    {
                        using (RegistryKey key = (string.IsNullOrEmpty(subPath) ? root : root.OpenSubKey(subPath, true)))
                        {
                            if (key != null)
                            {
                                object val = key.GetValue(oldName == "(Default)" ? "" : oldName);
                                RegistryValueKind kind = key.GetValueKind(oldName == "(Default)" ? "" : oldName);
                                key.DeleteValue(oldName == "(Default)" ? "" : oldName, false);
                                key.SetValue(newName == "(Default)" ? "" : newName, val, kind);
                                key.Close();
                                TvRegistry_AfterSelect(tvRegistry.SelectedNode, null);
                            }
                        }
                    }
                }
                catch (Exception ex) { MessageBox.Show("Error: " + ex.Message, "Error", MessageBoxButtons.OK, MessageBoxIcon.Error); }
                finally { if (root != null) root.Dispose(); }
            }
            else
            {
                if (tvRegistry.SelectedNode.Parent == null) { MessageBox.Show("Cannot rename root keys.", "Error", MessageBoxButtons.OK, MessageBoxIcon.Warning); return; }
                string oldName = tvRegistry.SelectedNode.Text;
                string newName = Interaction.InputBox("Rename key:", "Rename Key", oldName);
                if (string.IsNullOrWhiteSpace(newName) || newName == oldName) return;
                string parentPath = GetRegPath(tvRegistry.SelectedNode.Parent);
                RegistryKey root = null; string subPath = null;
                try
                {
                    root = GetRootKey(parentPath, out subPath);
                    if (root != null)
                    {
                        using (RegistryKey parent = (string.IsNullOrEmpty(subPath) ? root : root.OpenSubKey(subPath, true)))
                        {
                            if (parent != null)
                            {
                                string srcPath = parentPath + "\\" + oldName;
                                string dstPath = parentPath + "\\" + newName;
                                Process.Start("regedit.exe", "/e \"" + Path.GetTempPath() + "\\reg_export.reg\" \"" + srcPath + "\"");
                                System.Threading.Thread.Sleep(500);
                                parent.DeleteSubKeyTree(oldName);
                                Process.Start("regedit.exe", "\"" + Path.GetTempPath() + "\\reg_export.reg\"");
                                System.Threading.Thread.Sleep(500);
                                parent.Close();
                                tvRegistry.SelectedNode = tvRegistry.SelectedNode.Parent;
                                if (tvRegistry.SelectedNode != null) TvRegistry_AfterSelect(tvRegistry.SelectedNode, null);
                            }
                        }
                    }
                }
                catch (Exception ex) { MessageBox.Show("Error: " + ex.Message, "Error", MessageBoxButtons.OK, MessageBoxIcon.Error); }
                finally { if (root != null) root.Dispose(); }
            }
        }

        // ========== DRIVER UPDATE METHODS ==========

        private void CheckDriverUpdates()
        {
            if (lvDrivers.SelectedItems.Count > 0)
            {
                string drvName = lvDrivers.SelectedItems[0].Text;
                if (MessageBox.Show("Search online for updates for '" + drvName + "'?", "Check Driver Updates", MessageBoxButtons.YesNo, MessageBoxIcon.Question) == DialogResult.Yes)
                {
                    try { Process.Start("https://www.google.com/search?q=" + Uri.EscapeDataString(drvName + " Windows driver update download")); }
                    catch { }
                }
            }
            else
            {
                DialogResult choice = MessageBox.Show("Open Windows Update settings?", "Check Driver Updates", MessageBoxButtons.YesNoCancel, MessageBoxIcon.Question);
                if (choice == DialogResult.Yes)
                {
                    try { Process.Start("ms-settings:windowsupdate"); }
                    catch { try { Process.Start("control", "update"); } catch { } }
                }
                else if (choice == DialogResult.Cancel)
                {
                    try { Process.Start("https://www.catalog.update.microsoft.com/Search.aspx?q=driver"); }
                    catch { }
                }
            }
        }

        private void ToggleDriverState(bool enable)
        {
            if (lvDrivers.SelectedItems.Count == 0) { MessageBox.Show("Select a driver first.", "Driver", MessageBoxButtons.OK, MessageBoxIcon.Information); return; }
            string drvName = lvDrivers.SelectedItems[0].Text;
            string action = enable ? "ENABLE" : "DISABLE";
            if (MessageBox.Show(action + " driver '" + drvName + "'?\n\nNote: This requires administrator privileges.", "Driver " + action, MessageBoxButtons.YesNo, MessageBoxIcon.Warning) != DialogResult.Yes) return;
            try
            {
                ProcessStartInfo psi = new ProcessStartInfo();
                psi.FileName = "sc.exe";
                psi.Arguments = (enable ? "start " : "stop ") + "\"" + drvName + "\"";
                psi.Verb = "runas";
                psi.UseShellExecute = true;
                psi.WindowStyle = ProcessWindowStyle.Hidden;
                Process p = Process.Start(psi);
                p.WaitForExit(10000);
                if (p.ExitCode == 0)
                {
                    MessageBox.Show("Driver " + action.ToLower() + "d successfully.", "Success", MessageBoxButtons.OK, MessageBoxIcon.Information);
                    LoadDrivers();
                }
                else MessageBox.Show("Failed to " + action.ToLower() + " driver. Exit code: " + p.ExitCode, "Error", MessageBoxButtons.OK, MessageBoxIcon.Error);
            }
            catch (Exception ex) { MessageBox.Show("Error: " + ex.Message + "\n\nTry running as Administrator.", "Error", MessageBoxButtons.OK, MessageBoxIcon.Error); }
        }

        private void ExportDrivers()
        {
            if (lvDrivers.Items.Count == 0) return;
            using (var dlg = new SaveFileDialog { Filter = "CSV files (*.csv)|*.csv|Text files (*.txt)|*.txt", FileName = "drivers_" + DateTime.Now.ToString("yyyyMMdd") })
            {
                if (dlg.ShowDialog() == DialogResult.OK)
                {
                    try
                    {
                        var sb = new StringBuilder();
                        sb.AppendLine("Name,Display Name,Status,State,Start Mode,Service Type,Path,Description");
                        foreach (ListViewItem item in lvDrivers.Items)
                        {
                            var fields = new List<string>();
                            for (int i = 0; i < 8; i++) fields.Add("\"" + item.SubItems[i].Text.Replace("\"", "\"\"") + "\"");
                            sb.AppendLine(string.Join(",", fields));
                        }
                        File.WriteAllText(dlg.FileName, sb.ToString());
                        MessageBox.Show("Exported: " + dlg.FileName, "Export", MessageBoxButtons.OK, MessageBoxIcon.Information);
                    }
                    catch (Exception ex) { MessageBox.Show("Error: " + ex.Message, "Error", MessageBoxButtons.OK, MessageBoxIcon.Error); }
                }
            }
        }

