    // ========== MEMORY GRAPH CONTROL ==========

    public class MemoryGraphControl : Control
    {
        private List<int> dataPoints = new List<int>();
        private int maxPoints = 60;

        public MemoryGraphControl()
        {
            this.DoubleBuffered = true;
            this.ResizeRedraw = true;
        }

        public void AddDataPoint(int percent)
        {
            dataPoints.Add(percent);
            if (dataPoints.Count > maxPoints) dataPoints.RemoveAt(0);
        }

        protected override void OnPaint(PaintEventArgs e)
        {
            base.OnPaint(e);
            Graphics g = e.Graphics;
            g.SmoothingMode = SmoothingMode.AntiAlias;
            g.TextRenderingHint = System.Drawing.Text.TextRenderingHint.AntiAlias;

            int w = ClientSize.Width, h = ClientSize.Height;
            using (SolidBrush bg = new SolidBrush(Color.FromArgb(25, 28, 40)))
                g.FillRectangle(bg, this.ClientRectangle);

            // Grid lines
            using (Pen gridPen = new Pen(Color.FromArgb(50, 55, 75), 1))
            {
                for (int i = 0; i <= 4; i++)
                {
                    int y = h - (h * i / 4) - 20;
                    g.DrawLine(gridPen, 40, y, w - 10, y);
                    TextRenderer.DrawText(g, (i * 25) + "%", new Font("Segoe UI", 7f), new Rectangle(2, y - 6, 36, 12), Color.FromArgb(100, 110, 140), TextFormatFlags.Right);
                }
            }

            // Baseline
            using (Pen basePen = new Pen(Color.FromArgb(80, 90, 120), 1))
                g.DrawLine(basePen, 40, h - 20, w - 10, h - 20);

            // Data line
            if (dataPoints.Count > 1)
            {
                int graphW = w - 55;
                int graphH = h - 40;
                using (Pen linePen = new Pen(Color.FromArgb(80, 180, 255), 2) { StartCap = LineCap.Round, EndCap = LineCap.Round })
                using (Pen fillPen = new Pen(Color.FromArgb(40, 120, 200), 1))
                {
                    PointF[] points = new PointF[dataPoints.Count];
                    for (int i = 0; i < dataPoints.Count; i++)
                    {
                        float x = 42 + (float)i / maxPoints * graphW;
                        float y = h - 20 - (float)dataPoints[i] / 100 * graphH;
                        points[i] = new PointF(x, y);
                    }
                    if (points.Length > 1)
                    {
                        g.DrawLines(linePen, points);
                        // Fill under curve
                        using (GraphicsPath gp = new GraphicsPath())
                        {
                            gp.AddLines(points);
                            gp.AddLine(points[points.Length - 1].X, h - 20, points[0].X, h - 20);
                            gp.CloseFigure();
                            using (LinearGradientBrush fill = new LinearGradientBrush(new PointF(0, 0), new PointF(0, h - 20), Color.FromArgb(60, 80, 160, 255), Color.FromArgb(10, 20, 50, 80)))
                                g.FillPath(fill, gp);
                        }
                    }
                }
            }

            // Current value
            if (dataPoints.Count > 0)
            {
                int val = dataPoints[dataPoints.Count - 1];
                string txt = string.Format("Now: {0}%", val);
                TextRenderer.DrawText(g, txt, new Font("Segoe UI", 8f, FontStyle.Bold), new Rectangle(w - 90, 4, 80, 16), Color.FromArgb(180, 220, 255), TextFormatFlags.Right);
            }

            // Labels
            TextRenderer.DrawText(g, "Memory Usage (2s intervals)", new Font("Segoe UI", 7.5f), new Rectangle(42, 4, w - 50, 14), Color.FromArgb(120, 140, 180), TextFormatFlags.Left);
        }
    }

