    // For InputBox without Microsoft.VisualBasic dependency
    public static class Interaction
    {
        public static string InputBox(string prompt, string title, string defaultText)
        {
            Form form = new Form { Text = title, Size = new Size(400, 160), StartPosition = FormStartPosition.CenterParent, FormBorderStyle = FormBorderStyle.FixedDialog, MaximizeBox = false, MinimizeBox = false, ShowInTaskbar = false };
            Label lbl = new Label { Text = prompt, Location = new Point(12, 12), AutoSize = true };
            TextBox txt = new TextBox { Text = defaultText, Location = new Point(12, 36), Width = 360, BorderStyle = BorderStyle.FixedSingle };
            Button ok = new Button { Text = "OK", Location = new Point(210, 70), Size = new Size(75, 26), FlatStyle = FlatStyle.Flat, BackColor = Color.FromArgb(70, 120, 220), ForeColor = Color.White, FlatAppearance = { BorderSize = 0 } };
            Button cancel = new Button { Text = "Cancel", Location = new Point(295, 70), Size = new Size(75, 26), FlatStyle = FlatStyle.Flat, BackColor = Color.FromArgb(200, 200, 200), FlatAppearance = { BorderColor = Color.FromArgb(180,180,180) } };
            ok.DialogResult = DialogResult.OK; cancel.DialogResult = DialogResult.Cancel;
            form.Controls.AddRange(new Control[] { lbl, txt, ok, cancel });
            form.AcceptButton = ok; form.CancelButton = cancel;
            return form.ShowDialog() == DialogResult.OK ? txt.Text : null;
        }
    }

